#include<bits/stdc++.h>
#include<bits/extc++.h>
using namespace std;

int main()
{
    int n;
    scanf("%d",&n);
    __gnu_cxx::rope<int> v;
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        v.push_back(x);
    }
    while(n--)
    {
        int op,l,r,x;
        scanf("%d",&op);
        if(op==0)
        {
            scanf("%d%d",&l,&r);
            v.insert(l-1,r);
        }
        else
        {
            scanf("%d",&x);
            printf("%d\n",v[x-1]);
        }
    }
    return 0;
}
